/**
 * Calculates the 7 indices k_0, k_1, ..., k_6 in the 4x4 grid 
 * corresponding to the path taken, starting from (0,0).
 * @param {string} directions 
 * @returns {{K: number[], K_map: Map<number, number>}}
 */
const calculatePathIndices = (directions) => {
    const K = [];
    let r = 0;
    let c = 0;

    // Initial position (0, 0) -> Index 0
    K.push(0);

    for (const move of directions) {
        if (move === 'D') {
            r++;
        } else { // 'R'
            c++;
        }

        // Calculate the index k = r * 4 + c
        let k = r * 4 + c;

        // Only record indices within the 4x4 grid (0 to 15)
        if (k < 16) {
            K.push(k);
        }
    }

    const K_map = new Map(); // Map grid index k -> path step j (0 to 6)
    for (let j = 0; j < K.length; j++) {
        K_map.set(K[j], j);
    }

    return { K, K_map };
};

/**
 * Counts the number of good integers up to N.
 * @param {number} N 
 * @param {Map<string, number>} memo Cache for memoization
 * @param {number[]} K Path indices
 * @param {Map<number, number>} K_map Index to path step mapping
 * @returns {number} Count of good integers <= N
 */
const dpSolver = (N, K, K_map) => {
    if (N < 1) return 0;

    const N_str = String(N).padStart(16, '0');

    const memo = new Map();

    // index: current digit index (0 to 15)
    // isTight: boolean, if we are restricted by N_str
    // last_required_digit: the value of the last required digit (s_{k_{j-1}}), -1 if none set yet
    const dp = (index, isTight, last_required_digit) => {
        if (index === 16) {
            return 1;
        }

        const key = `${index}-${isTight ? 1 : 0}-${last_required_digit}`;
        if (memo.has(key)) {
            return memo.get(key);
        }

        const limit = isTight ? parseInt(N_str[index]) : 9;
        let count = 0;

        for (let d = 0; d <= limit; d++) {
            const newTight = isTight && (d === limit);
            let newLastRequiredDigit = last_required_digit;
            let isValid = true;

            if (K_map.has(index)) {
                const j = K_map.get(index);

                if (j > 0) {
                    // Constraint check: d must be >= the previously required digit (s_{k_{j-1}})
                    if (d < last_required_digit) {
                        isValid = false;
                    }
                }

                if (isValid) {
                    // This digit 'd' sets the new minimum threshold for future required digits
                    newLastRequiredDigit = d;
                }
            }

            if (isValid) {
                count += dp(index + 1, newTight, newLastRequiredDigit);
            }
        }

        memo.set(key, count);
        return count;
    };

    // Initial call: index 0, tight=true, last_required_digit=-1 (sentinel)
    return dp(0, true, -1);
};


function solve(l, r, directions) {
    const { K, K_map } = calculatePathIndices(directions);

    // We need a fresh memoization structure for each call to dpSolver
    // Since dpSolver manages its own memoization internally based on its scope, we just call it twice.

    const countR = dpSolver(r, K, K_map);
    const countLMinus1 = dpSolver(l - 1, K, K_map);

    return countR - countLMinus1;
}

